class Solution:
    def minimumBeautifulSubstrings(self, s: str) -> int:
        from functools import lru_cache

        # Precompute all powers of 5 in binary form up to length 15
        powers_of_5 = set()
        for i in range(0, 16):
            power = 5 ** i
            binary = bin(power)[2:]
            powers_of_5.add(binary)

        n = len(s)

        @lru_cache(None)
        def dp(i):
            if i == n:
                return 0
            res = float('inf')
            for j in range(i + 1, n + 1):
                substr = s[i:j]
                # Check for leading zeros
                if len(substr) > 1 and substr[0] == '0':
                    continue
                # Check if the substring is a power of 5
                if substr in powers_of_5:
                    res = min(res, 1 + dp(j))
            return res

        result = dp(0)
        return result if result != float('inf') else -1
